import asyncio
from anthropic import AsyncAnthropic

async_client = AsyncAnthropic()

async def analyze_transaction_async(txn: dict) -> dict:
    messages = [{"role": "user", "content": "Analyze:\n" + json.dumps(txn, default=str)}]
    try:
        while True:
            response = await async_client.messages.create(
                model="claude-opus-4-5", max_tokens=2048,
                system=SYSTEM_PROMPT, tools=TRANSACTION_TOOLS, messages=messages,
            )
            messages.append({"role": "assistant", "content": response.content})

            if response.stop_reason == "end_turn":
                for block in response.content:
                    if hasattr(block, "text"):
                        return json.loads(block.text)

            if response.stop_reason == "tool_use":
                # Execute all tool calls in this turn concurrently
                tool_calls = [b for b in response.content if b.type == "tool_use"]
                results = await asyncio.gather(
                    *[asyncio.to_thread(run_tool, b.name, b.input) for b in tool_calls]
                )
                messages.append({"role": "user", "content": [
                    {"type": "tool_result", "tool_use_id": b.id, "content": r}
                    for b, r in zip(tool_calls, results)
                ]})
