from pydantic import BaseModel, field_validator

class TransactionDecision(BaseModel):
    decision: str
    risk_score: int
    confidence: str
    rationale: str
    sar_required: bool
    sar_draft: str | None = None

    @field_validator("decision")
    @classmethod
    def valid_decision(cls, v: str) -> str:
        allowed = {"approve", "flag_for_review", "block"}
        if v not in allowed:
            raise ValueError(f"must be one of {allowed}")
        return v

    @field_validator("risk_score")
    @classmethod
    def valid_score(cls, v: int) -> int:
        if not (0 <= v <= 100):
            raise ValueError("risk_score must be 0-100")
        return v

